22	entity psi_fix_param_ram is
23	  generic(
24	    depth_g    : positive    := 1024;         -- memory depth
25	    fmt_g      : psi_fix_fmt_t := (1, 0, 15); -- fixed format
26	    behavior_g : string      := "RBW";        -- "RBW" = read-before-write, "WBR" = write-before-read
27	    init_g     : t_areal     := (0.0, 0.0)    -- First N parameters are initialized, others are zero
28	  );
29	  port(
30	    -- Port A
31	    ClkA  : in  std_logic                                        := '0';              -- clock port A
32	    AddrA : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0');  -- address port A
33	    WrA   : in  std_logic                                        := '0';              -- write enable A
34	    DinA  : in  std_logic_vector(psi_fix_size(fmt_g) - 1 downto 0) := (others => '0');-- data input A
35	    DoutA : out std_logic_vector(psi_fix_size(fmt_g) - 1 downto 0);                   -- data output A
36	    -- Port B
37	    ClkB  : in  std_logic                                        := '0';              -- clock port B
38	    AddrB : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0');  -- address port B
39	    WrB   : in  std_logic                                        := '0';              -- write enable B
40	    DinB  : in  std_logic_vector(psi_fix_size(fmt_g) - 1 downto 0) := (others => '0');-- data input B
41	    DoutB : out std_logic_vector(psi_fix_size(fmt_g) - 1 downto 0)                    -- data output B
42	  );
43	end entity;
44	
45	architecture rtl of psi_fix_param_ram is
46	
47	  -- memory array
48	  type mem_t is array (depth_g - 1 downto 0) of std_logic_vector(psi_fix_size(fmt_g) - 1 downto 0);
49	
50	  function GetInit return mem_t is
51	    variable mem_v : mem_t := (others => (others => '0'));
52	  begin
53	    for i in 0 to init_g'length - 1 loop
54	      mem_v(i) := psi_fix_from_real(init_g(i), fmt_g);
55	    end loop;
56	    return mem_v;
57	  end function;
58	
59	  shared variable mem : mem_t := GetInit;
60	
61	begin
62	
63	  assert behavior_g = "RBW" or behavior_g = "WBR" report "psi_fix_param_ram: behavior_g must be RBW or WBR" severity error;
64	
65	  -- Port A
66	  porta_p : process(ClkA)
67	  begin
68	    if rising_edge(ClkA) then
69	      if behavior_g = "RBW" then
70	        DoutA <= mem(to_integer(unsigned(AddrA)));
71	      end if;
72	      if WrA = '1' then
73	        mem(to_integer(unsigned(AddrA))) := DinA;
74	      end if;
75	      if behavior_g = "WBR" then
76	        DoutA <= mem(to_integer(unsigned(AddrA)));
77	      end if;
78	    end if;
79	  end process;
80	
81	  -- Port B
82	  portb_p : process(ClkB)
83	  begin
84	    if rising_edge(ClkB) then
85	      if behavior_g = "RBW" then
86	        DoutB <= mem(to_integer(unsigned(AddrB)));
87	      end if;
88	      if WrB = '1' then
89	        mem(to_integer(unsigned(AddrB))) := DinB;
90	      end if;
91	      if behavior_g = "WBR" then
92	        DoutB <= mem(to_integer(unsigned(AddrB)));
93	      end if;
94	    end if;
