186	  -- VHDL Only
187	  --------------------------------------------------------------------------
188	  function psi_fix_to_real(a    : std_logic_vector;
189	                        a_fmt : psi_fix_fmt_t)
190	  return real;
191	
192	  function psi_fix_round_from_string(s : string)
193	  return psi_fix_rnd_t;
194	
195	  function psi_fix_sat_from_string(s : string)
196	  return psi_fix_sat_t;
197	
198	  function psi_fix_fmt_from_string(str : string) return psi_fix_fmt_t;
199	
200	  function psi_fix_fmt_to_string(a_fmt : psi_fix_fmt_t) return string;
201	
202	end psi_fix_pkg;
203	
204	------------------------------------------------------------------------------
205	-- Package Body
206	------------------------------------------------------------------------------
207	package body psi_fix_pkg is
208	
209	  --------------------------------------------------------------------------
210	  -- Helpers
211	  --------------------------------------------------------------------------
212	  function psi_fix_choose_fmt(sel  : boolean;
213	                           fmt_A : psi_fix_fmt_t;
214	                           fmt_B : psi_fix_fmt_t)
215	  return psi_fix_fmt_t is
216	  begin
217	    if sel then
218	      return fmt_A;
219	    else
220	      return fmt_B;
221	    end if;
222	  end function;
223	
224	  function psi_fix_str_to_Int(str : string) return integer is
225	    variable Idx_v    : integer := str'low;
226	    variable IsNeg_v  : boolean := false;
227	    variable ValAbs_v : integer := 0;
228	  begin
229	    -- skip leading white-spaces
230	    while (Idx_v <= str'high) and str(Idx_v) = ' ' loop
231	      Idx_v := Idx_v + 1;
232	    end loop;
233	
234	    -- Check signal
235	    if (Idx_v <= str'high) and (str(Idx_v) = '-') then
236	      IsNeg_v := true;
237	      Idx_v   := Idx_v + 1;
238	    end if;
239	
240	    -- Parse Integer
241	    while (Idx_v <= str'high) and (str(Idx_v) <= '9') and (str(Idx_v) >= '0') loop
242	      ValAbs_v := ValAbs_v * 10 + (character'pos(str(Idx_v)) - character'pos('0'));
243	      Idx_v    := Idx_v + 1;
244	    end loop;
245	
246	    -- Return
247	    if IsNeg_v then
248	      return -ValAbs_v;
249	    else
250	      return ValAbs_v;
251	    end if;
252	  end function;
253	
254	  --------------------------------------------------------------------------
255	  -- Conversions between PSI and Enclustra Definitions
256	  --------------------------------------------------------------------------
257	  function psi_fix2_cl_fix(rnd : psi_fix_rnd_t)
258	  return FixRound_t is
259	  begin
260	    case rnd is
261	      when psi_fix_round => return NonSymPos_s;
262	      when psi_fix_trunc => return Trunc_s;
263	      when others => report "psi_fix_pkg: Unsupported Rounding Mode" severity error;
264	        return Trunc_s;
265	    end case;
266	  end function;
267	
268	  function psi_fix2_cl_fix(sat : psi_fix_sat_t)
269	  return FixSaturate_t is
270	  begin
271	    case sat is
272	      when psi_fix_sat  => return Sat_s;
273	      when psi_fix_wrap => return None_s;
274	      when others => report "psi_fix_pkg: Unsupported Saturation Mode" severity error;
275	        return None_s;
276	    end case;
277	  end function;
278	
279	  function psi_fix2_cl_fix(fmt : psi_fix_fmt_t)
280	  return FixFormat_t is
281	  begin
282	    return ((fmt.S = 1), fmt.I, fmt.F);
283	  end function;
284	
285	  function psi_fix2_cl_fix(fmts : psi_fix_fmt_array_t)
286	  return FixFormatArray_t is
287	    variable Fmts_v : FixFormatArray_t(fmts'range);
288	  begin
289	    for i in fmts'range loop
290	      Fmts_v(i) := psi_fix2_cl_fix(fmts(i));
291	    end loop;
292	    return Fmts_v;
293	  end function;
294	
295	  function cl_fix2_psi_fix(rnd : FixRound_t)
296	  return psi_fix_rnd_t is
297	  begin
298	    case rnd is
299	      when NonSymPos_s => return psi_fix_round;
300	      when Trunc_s     => return psi_fix_trunc;
301	      when others => report "psi_fix_pkg: Unsupported Rounding Mode (only Round/Trunc are supported)" severity error;
302	        return psi_fix_trunc;
303	    end case;
304	  end function;
305	
306	  function cl_fix2_psi_fix(sat : FixSaturate_t)
307	  return psi_fix_sat_t is
308	  begin
309	    case sat is
310	      when Sat_s  => return psi_fix_sat;
311	      when None_s => return psi_fix_wrap;
312	      when others => report "psi_fix_pkg: Unsupported Saturation Mode (only Sat/Wrap are supported)" severity error;
313	        return psi_fix_wrap;
314	    end case;
315	  end function;
316	
317	  function cl_fix2_psi_fix(fmt : FixFormat_t)
318	  return psi_fix_fmt_t is
319	  begin
320	    return (choose(fmt.Signed, 1, 0), fmt.Intbits, fmt.FracBits);
321	  end function;
322	
323	  function cl_fix2_psi_fix(fmts : FixFormatArray_t)
324	  return psi_fix_fmt_array_t is
325	    variable Fmts_v : psi_fix_fmt_array_t(fmts'range);
326	  begin
327	    for i in fmts'range loop
328	      Fmts_v(i) := cl_fix2_psi_fix(fmts(i));
329	    end loop;
330	    return Fmts_v;
331	  end function;
332	
333	  --------------------------------------------------------------------------
334	  -- Psi Fix Functionality
335	  --------------------------------------------------------------------------
336	  -- *** psi_fix_size ***
337	  function psi_fix_size(fmt : psi_fix_fmt_t)
338	  return integer is
339	  begin
340	    return cl_fix_width(psi_fix2_cl_fix(fmt));
341	  end function;
342	
343	  -- *** psi_fix_from_real ***
344	  function psi_fix_from_real(a    : real;
345	                          r_fmt : psi_fix_fmt_t)
346	  return std_logic_vector is
347	  begin
348	    -- assertions
349	    assert (r_fmt.S = 1) or (a >= 0.0) report "psi_fix_from_real: Unsigned format but negative number" severity error;
350	    -- implementation
351	    return cl_fix_from_real(a, psi_fix2_cl_fix(r_fmt));
352	  end function;
353	
354	  -- *** psi_fix_to_real ***
355	  function psi_fix_to_real(a    : std_logic_vector;
356	                        a_fmt : psi_fix_fmt_t)
357	  return real is
358	
359	  begin
360	    return cl_fix_to_real(a, psi_fix2_cl_fix(a_fmt));
361	  end function;
362	
363	  -- *** psi_fix_from_bits_as_int ***
364	  function psi_fix_from_bits_as_int(a    : integer;
365	                               a_fmt : psi_fix_fmt_t)
366	  return std_logic_vector is
367	  begin
368	    return cl_fix_from_bits_as_int(a, psi_fix2_cl_fix(a_fmt));
369	  end function;
370	
371	  -- *** psi_fix_get_bits_as_int ***
372	  function psi_fix_get_bits_as_int(a    : std_logic_vector;
373	                              a_fmt : psi_fix_fmt_t)
374	  return integer is
375	  begin
376	    return cl_fix_get_bits_as_int(a, psi_fix2_cl_fix(a_fmt));
377	  end function;
378	
379	  -- *** psi_fix_resize ***
380	  function psi_fix_resize(a    : std_logic_vector;
381	                        a_fmt : psi_fix_fmt_t;
382	                        r_fmt : psi_fix_fmt_t;
383	                        rnd  : psi_fix_rnd_t := psi_fix_trunc;
384	                        sat  : psi_fix_sat_t := psi_fix_wrap)
385	  return std_logic_vector is
386	  begin
387	    return cl_fix_resize(a, psi_fix2_cl_fix(a_fmt), psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
388	  end function;
389	
390	  -- *** psi_fix_add ***
391	  function psi_fix_add(a    : std_logic_vector;
392	                     a_fmt : psi_fix_fmt_t;
393	                     b    : std_logic_vector;
394	                     b_fmt : psi_fix_fmt_t;
395	                     r_fmt : psi_fix_fmt_t;
396	                     rnd  : psi_fix_rnd_t := psi_fix_trunc;
397	                     sat  : psi_fix_sat_t := psi_fix_wrap)
398	  return std_logic_vector is
399	  begin
400	    return cl_fix_add(a, psi_fix2_cl_fix(a_fmt),
401	                      b, psi_fix2_cl_fix(b_fmt),
402	                      psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
403	  end function;
404	
405	  -- *** psi_fix_sub ***
406	  function psi_fix_sub(a    : std_logic_vector;
407	                     a_fmt : psi_fix_fmt_t;
408	                     b    : std_logic_vector;
409	                     b_fmt : psi_fix_fmt_t;
410	                     r_fmt : psi_fix_fmt_t;
411	                     rnd  : psi_fix_rnd_t := psi_fix_trunc;
412	                     sat  : psi_fix_sat_t := psi_fix_wrap)
413	  return std_logic_vector is
414	  begin
415	    return cl_fix_sub(a, psi_fix2_cl_fix(a_fmt),
416	                      b, psi_fix2_cl_fix(b_fmt),
417	                      psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
418	  end function;
419	
420	  -- *** psi_fix_mult ***
421	  function psi_fix_mult(a    : std_logic_vector;
422	                      a_fmt : psi_fix_fmt_t;
423	                      b    : std_logic_vector;
424	                      b_fmt : psi_fix_fmt_t;
425	                      r_fmt : psi_fix_fmt_t;
426	                      rnd  : psi_fix_rnd_t := psi_fix_trunc;
427	                      sat  : psi_fix_sat_t := psi_fix_wrap)
428	  return std_logic_vector is
429	  begin
430	    return cl_fix_mult(a, psi_fix2_cl_fix(a_fmt),
431	                       b, psi_fix2_cl_fix(b_fmt),
432	                       psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
433	  end function;
434	
435	  -- *** psi_fix_abs ***
436	  function psi_fix_abs(a    : std_logic_vector;
437	                     a_fmt : psi_fix_fmt_t;
438	                     r_fmt : psi_fix_fmt_t;
439	                     rnd  : psi_fix_rnd_t := psi_fix_trunc;
440	                     sat  : psi_fix_sat_t := psi_fix_wrap)
441	  return std_logic_vector is
442	  begin
443	    return cl_fix_abs(a, psi_fix2_cl_fix(a_fmt), psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
444	  end function;
445	
446	  -- *** psi_fix_neg ***
447	  function psi_fix_neg(a    : std_logic_vector;
448	                     a_fmt : psi_fix_fmt_t;
449	                     r_fmt : psi_fix_fmt_t;
450	                     rnd  : psi_fix_rnd_t := psi_fix_trunc;
451	                     sat  : psi_fix_sat_t := psi_fix_wrap)
452	  return std_logic_vector is
453	  begin
454	    return cl_fix_neg(a, psi_fix2_cl_fix(a_fmt), '1', psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd), psi_fix2_cl_fix(sat));
455	  end function;
456	
457	  -- *** psi_fix_shift_left ***
458	  -- PsiFix specific implementation since cl_fix implementation is not synthesizable for dynamic shifts when using Xilinx Vivado tools
459	  function psi_fix_shift_left(a        : std_logic_vector;
460	                           a_fmt     : psi_fix_fmt_t;
461	                           shift    : integer;
462	                           maxShift : integer;
463	                           r_fmt     : psi_fix_fmt_t;
464	                           rnd      : psi_fix_rnd_t := psi_fix_trunc;
465	                           sat      : psi_fix_sat_t := psi_fix_wrap;
466	                           dynamic  : boolean     := False)
467	  return std_logic_vector is
468	    constant FullFmt_c : psi_fix_fmt_t := (max(a_fmt.S, r_fmt.S), max(a_fmt.I + maxShift, r_fmt.I), max(a_fmt.F, r_fmt.F));
469	    variable FullA_v   : std_logic_vector(psi_fix_size(FullFmt_c) - 1 downto 0);
470	    variable FullOut_v : std_logic_vector(FullA_v'range);
471	  begin
472	    assert shift >= 0 report "psi_fix_shift_left: Shift must be >= 0" severity error;
473	    assert shift <= maxShift report "psi_fix_shift_left: Shift must be <= maxShift" severity error;
474	    FullA_v := psi_fix_resize(a, a_fmt, FullFmt_c);
475	    if not dynamic then
476	      FullOut_v := shift_left(FullA_v, shift);
477	    else
478	      for i in 0 to maxShift loop
479	        if i = shift then
480	          FullOut_v := shift_left(FullA_v, i);
481	        end if;
482	      end loop;
483	    end if;
484	    return psi_fix_resize(FullOut_v, FullFmt_c, r_fmt, rnd, sat);
485	  end function;
486	
487	  -- *** psi_fix_shift_right ***
488	  -- PsiFix specific implementation since cl_fix implementation is not synthesizable for dynamic shifts when using Xilinx Vivado tools
489	  function psi_fix_shift_right(a        : std_logic_vector;
490	                            a_fmt     : psi_fix_fmt_t;
491	                            shift    : integer;
492	                            maxShift : integer;
493	                            r_fmt     : psi_fix_fmt_t;
494	                            rnd      : psi_fix_rnd_t := psi_fix_trunc;
495	                            sat      : psi_fix_sat_t := psi_fix_wrap;
496	                            dynamic  : boolean     := False)
497	  return std_logic_vector is
498	    constant FullFmt_c : psi_fix_fmt_t := (max(a_fmt.S, r_fmt.S), max(a_fmt.I, r_fmt.I), max(a_fmt.F + maxShift, r_fmt.F + 1)); -- Additional bit for rounding
499	    variable FullA_v   : std_logic_vector(psi_fix_size(FullFmt_c) - 1 downto 0);
500	    variable FullOut_v : std_logic_vector(FullA_v'range);
501	  begin
502	    assert shift >= 0 report "psi_fix_shift_right: Shift must be >= 0" severity error;
503	    assert shift <= maxShift report "psi_fix_shift_right: Shift must be <= maxShift" severity error;
504	    FullA_v := psi_fix_resize(a, a_fmt, FullFmt_c);
505	    if not dynamic then
506	      if a_fmt.S = 1 then
507	        FullOut_v := shift_right(FullA_v, shift, FullA_v(FullA_v'left));
508	      else
509	        FullOut_v := shift_right(FullA_v, shift, '0');
510	      end if;
511	    else
512	      for i in 0 to maxShift loop       -- make a loop to ensure the shift is a constant (required by the tools)
513	        if i = shift then
514	          if a_fmt.S = 1 then
515	            FullOut_v := shift_right(FullA_v, i, FullA_v(FullA_v'left));
516	          else
517	            FullOut_v := shift_right(FullA_v, i, '0');
518	          end if;
519	        end if;
520	      end loop;
521	    end if;
522	    return psi_fix_resize(FullOut_v, FullFmt_c, r_fmt, rnd, sat);
523	  end function;
524	
525	  -- *** psi_fix_upper_bound_stdlv ***
526	  function psi_fix_upper_bound_stdlv(fmt : psi_fix_fmt_t)
527	  return std_logic_vector is
528	  begin
529	    return cl_fix_max_value(psi_fix2_cl_fix(fmt));
530	  end function;
531	
532	  -- *** psi_fix_lower_bound_stdlv ***
533	  function psi_fix_lower_bound_stdlv(fmt : psi_fix_fmt_t)
534	  return std_logic_vector is
535	  begin
536	    return cl_fix_min_value(psi_fix2_cl_fix(fmt));
537	  end function;
538	
539	  -- *** psi_fix_upper_bound_Real ***
540	  function psi_fix_upper_bound_Real(fmt : psi_fix_fmt_t)
541	  return real is
542	  begin
543	    return cl_fix_max_real(psi_fix2_cl_fix(fmt));
544	  end function;
545	
546	  -- *** psi_fix_lower_bound_Real ***
547	  function psi_fix_lower_bound_Real(fmt : psi_fix_fmt_t)
548	  return real is
549	  begin
550	    return cl_fix_min_real(psi_fix2_cl_fix(fmt));
551	  end function;
552	
553	  -- *** psi_fix_in_range ***
554	  function psi_fix_in_range(a    : std_logic_vector;
555	                         a_fmt : psi_fix_fmt_t;
556	                         r_fmt : psi_fix_fmt_t;
557	                         rnd  : psi_fix_rnd_t := psi_fix_trunc)
558	  return boolean is
559	  begin
560	    return cl_fix_in_range(a, psi_fix2_cl_fix(a_fmt), psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd));
561	  end function;
562	
563	  -- *** psi_fix_round_from_string ***
564	  function psi_fix_round_from_string(s : string)
565	  return psi_fix_rnd_t is
566	  begin
567	    if s = "psi_fix_round" or s = "psifixround" then
568	      return psi_fix_round;
569	    elsif s = "psi_fix_trunc" or s = "psifixtrunc" then
570	      return psi_fix_trunc;
571	    end if;
572	    report "psi_fix_round_from_string: Illegal value - " & s severity error;
573	    return psi_fix_trunc;
574	  end function;
575	
576	  -- *** psi_fix_sat_from_string ***
577	  function psi_fix_sat_from_string(s : string)
578	  return psi_fix_sat_t is
579	  begin
580	    if s = "psi_fix_sat" or s = "psifixsat" then
581	      return psi_fix_sat;
582	    elsif s = "psi_fix_wrap" or s = "psifixwrap" then
583	      return psi_fix_wrap;
584	    end if;
585	    report "psi_fix_sat_from_string: Illegal value - " & s severity error;
586	    return psi_fix_wrap;
587	  end function;
588	
589	  -- *** psi_fix_compare ***
590	  -- Allowed comparisons: "a=b", "a<b", "a>b", "a<=b", "a>=b", "a!=b"
591	  function psi_fix_compare(comparison : string;
592	                         a          : std_logic_vector;
593	                         a_fmt       : psi_fix_fmt_t;
594	                         b          : std_logic_vector;
595	                         b_fmt       : psi_fix_fmt_t) return boolean is
596	  begin
597	    return cl_fix_compare(comparison, a, psi_fix2_cl_fix(a_fmt), b, psi_fix2_cl_fix(b_fmt));
598	  end function;
599	
600	  -- *** psi_fix_fmt_from_string ***
601	  function psi_fix_fmt_from_string(str : string) return psi_fix_fmt_t is
602	    variable Format_v         : psi_fix_fmt_t;
603	    variable OpenBraceIdx_v   : integer := -1;
604	    variable FirstCommaIdx_v  : integer := -1;
605	    variable SecondCommaIdx_v : integer := -1;
606	    variable CloseBraceIdx_v  : integer := -1;
607	  begin
608	    -- Parse Format
609	    for i in str'low to str'high loop
610	      if (OpenBraceIdx_v = -1) and (str(i) = '(') then
611	        OpenBraceIdx_v := i;
612	      elsif (FirstCommaIdx_v = -1) and (str(i) = ',') then
613	        FirstCommaIdx_v := i;
614	      elsif (SecondCommaIdx_v = -1) and (str(i) = ',') then
615	        SecondCommaIdx_v := i;
616	      elsif (CloseBraceIdx_v = -1) and (str(i) = ')') then
617	        CloseBraceIdx_v := i;
618	      end if;
619	    end loop;
620	    assert OpenBraceIdx_v >= 0 report "psi_fix_fmt_from_string: No opening brace found" severity error;
621	    assert FirstCommaIdx_v >= 0 report "psi_fix_fmt_from_string: First comma not found" severity error;
622	    assert SecondCommaIdx_v >= 0 report "psi_fix_fmt_from_string: Second comman not found" severity error;
623	    assert CloseBraceIdx_v >= 0 report "psi_fix_fmt_from_string: No closing brace found" severity error;
624	    Format_v.S := psi_fix_str_to_int(str(OpenBraceIdx_v + 1 to FirstCommaIdx_v - 1));
625	    Format_v.I := psi_fix_str_to_int(str(FirstCommaIdx_v + 1 to SecondCommaIdx_v - 1));
626	    Format_v.F := psi_fix_str_to_int(str(SecondCommaIdx_v + 1 to CloseBraceIdx_v - 1));
627	    assert (Format_v.S = 0) or (Format_v.S = 1) report "psi_fix_fmt_from_string: Sign must be 1 or 0" severity error;
628	    return Format_v;
629	  end function;
630	
631	  -- *** psi_fix_fmt_to_string ***
632	  function psi_fix_fmt_to_string(a_fmt : psi_fix_fmt_t) return string is
633	  begin
634	    return "(" & integer'image(a_fmt.S) & ", " & integer'image(a_fmt.I) & ", " & integer'image(a_fmt.F) & ")";
635	  end function;
636	
637	end psi_fix_pkg;
638	
